nodes.outputScript:
if (output.decision === 'Approved') {
  setOutput(workflow.currentPlan);
} else if (output.decision === 'Rejected') {
  setWorkflow('latestRejection', output.text);
  var prior = workflow.rejectionHistory || '';
  var entry = '## Round ' + round + '\n' + output.text;
  setWorkflow('rejectionHistory', prior ? prior + '\n\n' + entry : entry);
}

